#nullable enable // autogenerated  

using System.Collections.Generic;
using MVZ2.GameContent.Detections;
using MVZ2.Vanilla;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Effects
{
    [AutoEntityBehaviourDefinition(VanillaEffectNames.petrifyLaser)]
    public class PetrifyLaser : EntityBehaviourDefinition
    {
        public PetrifyLaser(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            entity.PlaySound(VanillaSoundID.scifiLaser);
            detectBuffer.Clear();
            laserDetector.DetectEntities(entity, detectBuffer);
            bool soundPlayed = false;
            foreach (var target in detectBuffer)
            {
                if (!entity.GetProperty<bool>(PROP_ULTIMATE))
                {
                    if (!target.CanDeactive())
                        continue;
                    if (target.Type == EntityTypes.BOSS)
                        continue;
                }
                // 按目标分类决定石化时长  
                var duration = GetPetrifyDuration(target);
                target.InflictPetrified(duration, new EntitySourceReference(entity));
                var spawnParams = target.GetSpawnParams();
                spawnParams.SetProperty(EngineEntityProps.TINT, Color.gray);
                target.Spawn(VanillaEffectID.smokeCluster, target.GetCenter(), spawnParams);
                if (!soundPlayed)
                {
                    target.PlaySound(VanillaSoundID.giantSpike);
                    target.PlaySound(VanillaSoundID.petrified);
                    soundPlayed = true;
                }
            }
        }

        // 根据敌人分类返回石化帧数：突变类、载具类减半，其余为默认  
        private static int GetPetrifyDuration(Entity target)
        {
            int baseDuration = Ticks.FromSeconds(PETRIFY_DURATION_SECONDS);
            // 注意：核对读取分类的确切 API 与分类 ID 的构造方式  
            var category = target.GetProperty<NamespaceID>(VanillaEntityProps.CATEGORY);
            if (category == MutantCategory || category == VehicleCategory)
                return baseDuration / 2;
            return baseDuration;
        }

        public const float PETRIFY_DURATION_SECONDS = 10f;
        public static Detector laserDetector = new CollisionDetector(true);
        public static readonly VanillaEntityPropertyMeta<bool> PROP_ULTIMATE = new VanillaEntityPropertyMeta<bool>("ultimate");
        public List<Entity> detectBuffer = new List<Entity>();

        // 分类 ID（对应 almanac.xml 里的 mvz2:Category 枚举值）  
        private static readonly NamespaceID MutantCategory = new NamespaceID(VanillaMod.spaceName, "Mutant_Exp");
        private static readonly NamespaceID VehicleCategory = new NamespaceID(VanillaMod.spaceName, "Vehicle_Exp");
    }
}
